import React from "react";
import "./drawer.scss";

import logo from "../../images/razer-ths-logo.svg";
import burger_close from "../../images/menu-close.png";
import { Context } from "../../context";
import { NavLink } from "react-router-dom";

const DrawerComponent = () => {
  const { setMobile } = React.useContext(Context);

  return (
    <div style={{ maxWidth: "90%", margin: "0 auto" }}>
      <div className="drawer-header">
        <img
          className="close"
          src={burger_close}
          alt=""
          onClick={() => {
            setMobile(false);
            document.body.style.overflowY = "scroll";
          }}
        />
        <img className="logo" src={logo} alt="" />
      </div>
      <div className="drawer-body">
        <input type="text" placeholder="Search razer.com" />

        {/*Change span to <Link to='route'></Link>*/}

        <div className="navigate-links">
          <NavLink
            to="/pc"
            onClick={() => {
              setMobile(false);
              document.body.style.overflowY = "scroll";
            }}
          >
            PC
          </NavLink>
          <NavLink
            to="/mobile"
            onClick={() => {
              setMobile(false);
              document.body.style.overflowY = "scroll";
            }}
          >
            Mobile
          </NavLink>
          <NavLink
            to="/"
            onClick={() => {
              setMobile(false);
              document.body.style.overflowY = "scroll";
            }}
          >
            Home
          </NavLink>
          <NavLink
            to="/services"
            onClick={() => {
              setMobile(false);
              document.body.style.overflowY = "scroll";
            }}
          >
            Services
          </NavLink>
          <NavLink
            to="/store"
            onClick={() => {
              setMobile(false);
              document.body.style.overflowY = "scroll";
            }}
          >
            Store
          </NavLink>
          {!localStorage.getItem("access") ? (
            <>
              <NavLink
                onClick={() => {
                  setMobile(false);
                  document.body.style.overflowY = "scroll";
                }}
                className="user"
                to="/sign-up"
              >
                Sign up
              </NavLink>
              <NavLink
                onClick={() => {
                  setMobile(false);
                  document.body.style.overflowY = "scroll";
                }}
                className="log_out"
                to="/sign-in"
              >
                Log in
              </NavLink>
            </>
          ) : (
            <a className="log_out"
              onClick={() => {
                window.localStorage.removeItem("access");
                window.location.reload();
              }}
            >
              Log out
            </a>
          )}
        </div>
      </div>
    </div>
  );
};

export default DrawerComponent;
